import React, { useState } from 'react';
import { Plus, Trash2, Edit2, Check, X } from 'lucide-react';

const AdminServices = ({ services, onUpdate }) => {
  const [newService, setNewService] = useState({ title: '', description: '' });
  const [editingId, setEditingId] = useState(null);
  const [editForm, setEditForm] = useState({ title: '', description: '' });

  const handleAdd = (e) => {
    e.preventDefault();
    if (!newService.title) return;
    const updated = [...services, { ...newService, id: Date.now() }];
    onUpdate(updated);
    setNewService({ title: '', description: '' });
  };

  const handleDelete = (id) => {
    const updated = services.filter(s => s.id !== id);
    onUpdate(updated);
  };

  const startEdit = (service) => {
    setEditingId(service.id);
    setEditForm({ title: service.title, description: service.description });
  };

  const saveEdit = (id) => {
    const updated = services.map(s => s.id === id ? { ...s, ...editForm } : s);
    onUpdate(updated);
    setEditingId(null);
  };

  return (
    <div className="max-w-4xl mx-auto py-10">
      <h2 className="text-3xl font-bold mb-8 gold-text-gradient">Manage Services</h2>

      <div className="glass p-6 rounded-2xl mb-8 border border-yellow-500/20">
        <h3 className="text-xl font-bold mb-4">Add New Service</h3>
        <form onSubmit={handleAdd} className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <input
            type="text"
            placeholder="Service Title (e.g. AC Repair)"
            className="bg-black/30 border border-gray-700 rounded-lg p-3 focus:border-yellow-500 outline-none"
            value={newService.title}
            onChange={(e) => setNewService({...newService, title: e.target.value})}
            required
          />
          <input
            type="text"
            placeholder="Short Description"
            className="bg-black/30 border border-gray-700 rounded-lg p-3 focus:border-yellow-500 outline-none"
            value={newService.description}
            onChange={(e) => setNewService({...newService, description: e.target.value})}
          />
          <button type="submit" className="md:col-span-2 gold-gradient text-black font-bold py-3 rounded-lg flex items-center justify-center gap-2">
            <Plus size={20} /> Add Service to Home Page
          </button>
        </form>
      </div>

      <div className="space-y-4">
        {services.map((service) => (
          <div key={service.id} className="glass p-4 rounded-xl flex items-center justify-between border border-white/5">
            {editingId === service.id ? (
              <div className="flex-grow flex gap-4 mr-4">
                <input
                  type="text"
                  className="bg-black/50 border border-yellow-500 rounded p-2 flex-grow"
                  value={editForm.title}
                  onChange={(e) => setEditForm({...editForm, title: e.target.value})}
                />
                <input
                  type="text"
                  className="bg-black/50 border border-yellow-500 rounded p-2 flex-grow"
                  value={editForm.description}
                  onChange={(e) => setEditForm({...editForm, description: e.target.value})}
                />
              </div>
            ) : (
              <div className="flex-grow">
                <h4 className="font-bold text-lg">{service.title}</h4>
                <p className="text-gray-400 text-sm">{service.description || 'Professional service with guarantee.'}</p>
              </div>
            )}

            <div className="flex gap-2">
              {editingId === service.id ? (
                <>
                  <button onClick={() => saveEdit(service.id)} className="p-2 text-green-500 hover:bg-green-500/10 rounded"><Check size={20} /></button>
                  <button onClick={() => setEditingId(null)} className="p-2 text-gray-500 hover:bg-gray-500/10 rounded"><X size={20} /></button>
                </>
              ) : (
                <>
                  <button onClick={() => startEdit(service)} className="p-2 text-yellow-500 hover:bg-yellow-500/10 rounded"><Edit2 size={20} /></button>
                  <button onClick={() => handleDelete(service.id)} className="p-2 text-red-500 hover:bg-red-500/10 rounded"><Trash2 size={20} /></button>
                </>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default AdminServices;
